using UnityEngine;

public class Physics2DExample : MonoBehaviour
{
    public Rigidbody2D rb;
    public float moveSpeed = 5f;
    public float jumpForce = 10f;

    private bool isGrounded = false;

    void Start()
    {
        // Get Rigidbody2D component
        rb = GetComponent<Rigidbody2D>();

        if (rb == null)
        {
            Debug.LogError("Rigidbody2D is required!");
        }

        // Set physics properties
        rb.gravityScale = 2f;
        rb.drag = 0.5f;
        rb.angularDrag = 0.05f;
        rb.freezeRotation = true;

        Debug.Log("Physics initialized!");
    }

    void Update()
    {
        // Handle input
        float horizontal = Input.GetAxis("Horizontal");

        // Jump
        if (Input.GetButtonDown("Jump") && isGrounded)
        {
            rb.AddForce(Vector2.up * jumpForce, ForceMode2D.Impulse);
            isGrounded = false;
        }
    }

    void FixedUpdate()
    {
        // Physics-based movement (use FixedUpdate)
        float horizontal = Input.GetAxis("Horizontal");

        // Set velocity
        Vector2 velocity = rb.velocity;
        velocity.x = horizontal * moveSpeed;
        rb.velocity = velocity;
    }

    void OnCollisionEnter2D(Collision2D collision)
    {
        if (collision.gameObject.CompareTag("Ground"))
        {
            isGrounded = true;
        }
    }

    // Example: Apply a force
    public void Push(Vector2 direction, float force)
    {
        rb.AddForce(direction * force, ForceMode2D.Impulse);
    }

    // Example: Set velocity directly
    public void SetVelocity(Vector2 newVelocity)
    {
        rb.velocity = newVelocity;
    }

    // Example: Add a torque (rotation)
    public void AddTorque(float torque)
    {
        rb.AddTorque(torque);
    }

    // Example: Check if moving
    public bool IsMoving()
    {
        return rb.velocity.magnitude > 0.1f;
    }
}

